from typing import List
from azure.ai.projects import AgentExtension

class EnterpriseGroundingFilter(AgentExtension):
    APPROVED_SOURCES = [
        "https://approved.bing.com",
        "azure://approved-storage.blob.core.windows.net"
    ]

    def filter_grounding_sources(self, sources: List[str]) -> List[str]:
        return [s for s in sources if any(approved in s for approved in self.APPROVED_SOURCES)]

    def validate_grounding_content(self, content: str) -> bool:
        banned_patterns = [
            r'sas_token=[^\s]+',
            r'azure://(?!approved)',
            r'\\internal-share\\'
        ]
        return not any(re.search(p, content) for p in banned_patterns)

# Register with agent
agent.add_extension(EnterpriseGroundingFilter())

