from vex_sdk import VexAgentMonitor
from azure.ai.projects import AgentClient

# Install: pip install azure-ai-projects vex-sdk

vex_monitor = VexAgentMonitor(
    azure_tenant_id="your-tenant-id",
    policies={
        "auth_drift": {
            "threshold": 300,  # 5min token expiry
            "auto_remediate": True
        },
        "rbac_violations": {
            "roles": ["Storage Blob Data Contributor", "Cognitive Services Contributor"],
            "block_on_violation": True
        },
        "grounding_dlp": {
            "banned_patterns": [r'sas_token', r'azure://(?!approved)'],
            "approved_sources": ["https://approved.bing.com"]
        }
    }
)

# Integrate with Azure Agent Service
client = AgentClient(endpoint="https://your-project.agents.azure.com")

@vex_monitor.trace()
def monitored_agent_thread(thread_id):
    # All tool calls, grounding, and auth events auto-monitored
    messages = client.list_messages(thread_id)
    for msg in messages:
        if msg.content.get('tool_calls'):
            vex_monitor.validate_tool_auth(msg)
    return messages

# Vex auto-generates compliance reports and remediation actions
vex_monitor.start_azure_monitoring(client)
